Rule.Source:
    import sailpoint.api.ObjectUtil;
  import sailpoint.tools.Message;
  import sailpoint.object.EmailTemplate;
  import sailpoint.object.EmailOptions;
  import sailpoint.object.Identity;
  import sailpoint.object.Workflow;
  import sailpoint.object.Workflow.Step;
  import sailpoint.object.ProvisioningPlan;
  import sailpoint.object.ProvisioningProject;
  import sailpoint.object.ProvisioningResult;
  import sailpoint.object.WorkflowCase;
  import sailpoint.object.WorkItem;
  import sailpoint.workflow.WorkflowContext;
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;
  import org.apache.log4j.Logger;
  import java.lang.StringBuilder;

  private String buildAlertWorkItem(WorkflowContext wfcontext, String identityName, StringBuilder errorString) {

    import sailpoint.object.Attributes;
    import sailpoint.object.Application;
    import sailpoint.object.ApprovalItem;
    import sailpoint.object.ApprovalSet;
    import sailpoint.object.Identity;
    import sailpoint.object.Form;
    import sailpoint.object.WorkItem;
    import sailpoint.persistence.Sequencer;

    Calendar expiration = Calendar.getInstance();  

    Form refForm = context.getObjectByName(Form.class, "Failed Workflow Alert");

    String wfName = wfcontext.getWorkflow().getName();
    WorkflowCase wfCase = wfcontext.getWorkflowCase();
    String wfCaseName = wfcase.getName();
    String currentStepId = wfcontext.getWorkflow().getCurrentStep();
    Workflow.Step currentStep = wfcontext.getWorkflow().findStepById(currentStepId, true);

    Identity refIdentity = context.getObjectByName(Identity.class, identityName);
    Identity requester = context.getObjectByName(Identity.class, "IDM Team");

    WorkItem item = new WorkItem();
    item.setType(WorkItem.Type.ManualAction);
    item.setOwner(requester);
    item.setRequester(requester);
    Sequencer sequencer = new Sequencer();
    item.setName(sequencer.generateId(context, item));
    item.setRenderer("workflow.xhtml");
    item.setLevel(WorkItem.Level.Normal);
    item.setDescription("Failed Workflow Alert: " + wfCaseName);
    item.setHandler("sailpoint.api.Workflower");
    item.setForm(refForm);

    Attributes attributes = new Attributes();
    item.setAttributes(attributes);

    attributes.put("workItemForm", refForm);
    attributes.put("identityName", identityName);
    attributes.put("identityDisplayName", refIdentity.getDisplayName());
    attributes.put("workflowName", wfName);
    attributes.put("workflowCaseName", wfCaseName);
    attributes.put("lastStep", currentStep.getName());
    attributes.put("errorMessage", errorString.toString());

    context.startTransaction();
    context.saveObject(item);
    context.commitTransaction();
    
    return item.getName();

  }

  Logger loggerVar = Logger.getLogger("sailpoint.ascension.rules.gsuite.beforeprov");

  loggerVar.debug("## ENTERING RULE: Rule-Ascension-FinalizeWorkflow ##");

  List errors = wfcontext.getWorkflowCase().getErrors();
  List warnings = wfcontext.getWorkflowCase().getWarnings();

  if (project != null) {

    List plans =  project.getPlans();

    ProvisioningResult provResult = null;

    if(plans != null) {

      for (ProvisioningPlan provPlan  : plans) {

        provResult = provPlan.getResult();

        if(provResult != null) {

          if(!provResult.isCommitted() || provResult.isFailed()) {

            errors.addAll(provResult.getErrors());
            warnings.addAll(provResult.getWarnings());

          }

        }

      }

    }

  }

  if(errors != null) {

    StringBuilder errorString = new StringBuilder();

    for (Message e : errors) {

      loggerVar.debug("WorkflowCaseError: " + e.toString());

      errorString.append(e.toString());
      errorString.append("\n");

    }
    
    String workItemId = buildAlertWorkItem(wfcontext, identityName, errorString);
    
    WorkItem workItem = context.getObjectByName(WorkItem.class, workItemId);
    
    String workItemName = workItem.getDescription();
    
    Map emailArgs = new HashMap();
    emailArgs.put("workItem", workItem);
    emailArgs.put("workItemName", workItemName);
    List emailRecipientAddresses = ObjectUtil.getEffectiveEmails(context, context.getObjectByName(Identity.class, "IDM Team"));
    EmailTemplate emailTemplate = context.getObjectByName(EmailTemplate.class, "Ascension-EmailTemplate-FailedWorkflowAlert");
    EmailOptions emailOps = new EmailOptions(emailRecipientAddresses, emailArgs);
    
    context.sendEmailNotification(emailTemplate, emailOps);
    
//    context.decache(workItem);


  } else {

    loggerVar.debug("No Errors Recorded");

  }

  if(warnings != null) {

    for (Message w : warnings) {

      loggerVar.debug("WorkflowCaseWarn: " + w.toString());

    }

  } else {

    loggerVar.debug("No Warnings Recorded");

  }

  loggerVar.debug("## EXITING RULE: Rule-Ascension-FinalizeWorkflow ##");
